import React, { useState, useEffect } from 'react';
import {
  Paper,
  Typography,
  Box,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Chip,
  IconButton,
  Tooltip,
  CircularProgress,
  useTheme,
  Dialog,
  DialogContent,
  DialogTitle,
  Alert,
  Button,
  Skeleton
} from '@mui/material';
import {
  TrendingUp,
  TrendingDown,
  Refresh,
  Schedule,
  Close,
  Share,
  ContentCopy,
  Download,
  Warning,
  Lock
} from '@mui/icons-material';
import pnlBackground from '../../assets/pnl-background.png';
import dashboardService from '../../services/dashboardService';
import html2canvas from 'html2canvas';

const OpenPositions = ({ user, hideValues = false }) => {
  const theme = useTheme();
  const [positions, setPositions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [refreshing, setRefreshing] = useState(false);
  const [progress, setProgress] = useState(0);
  const [shareModalOpen, setShareModalOpen] = useState(false);
  const [selectedPosition, setSelectedPosition] = useState(null);
  const [closingPosition, setClosingPosition] = useState(null);
  const [debugInfo, setDebugInfo] = useState('');

  // Timer visual de 30 segundos
  useEffect(() => {
    // Iniciar o progresso imediatamente
    setProgress(0);

    // Animação contínua do progresso
    const progressInterval = setInterval(() => {
      setProgress(prev => {
        if (prev >= 100) {
          return 0; // Reinicia o ciclo
        }
        return prev + (100 / 300); // 30 segundos = 300 décimos
      });
    }, 100); // Atualiza a cada 100ms

    return () => clearInterval(progressInterval);
  }, []);

  useEffect(() => {
    loadPositions();

    // Timer para atualização automática a cada 30 segundos
    const interval = setInterval(() => {
      loadPositions();
    }, 30000); // 30 segundos

    // Cleanup do timer quando o componente for desmontado
    return () => clearInterval(interval);
  }, []);

  const loadPositions = async () => {
    try {
      setError('');
      console.log('OpenPositions - Carregando posições...');

      const response = await dashboardService.getOpenPositions();
      console.log('OpenPositions - Resposta recebida:', response);

      if (response && response.success) {
        const positionsData = response.data || [];
        console.log('OpenPositions - Posições encontradas:', positionsData);
        setPositions(positionsData);
        setDebugInfo(`${positionsData.length} posições carregadas`);
      } else {
        const errorMsg = response?.message || 'Erro desconhecido ao carregar posições';
        console.log('OpenPositions - Erro na resposta:', errorMsg);
        setError(errorMsg);
        setDebugInfo(`Erro: ${errorMsg}`);
      }
    } catch (error) {
      console.error('OpenPositions - Erro ao carregar posições:', error);

      // Verificar se é erro de autenticação
      if (error.message === 'Login necessário' || error.status === 401) {
        setError('Sessão expirada. Você será redirecionado para o login.');
        setDebugInfo('Erro de autenticação');
        // O interceptador já vai lidar com o redirecionamento
      } else {
        const errorMsg = error.message || 'Erro ao conectar com o servidor';
        setError(errorMsg);
        setDebugInfo(`Erro de conexão: ${errorMsg}`);
      }
    } finally {
      setLoading(false);
    }
  };

  const handleClosePosition = async (position) => {
    try {
      setClosingPosition(position.symbol);
      const response = await dashboardService.closePosition(position.symbol, position.side);

      if (response.success) {
        // Recarregar posições após fechar
        await loadPositions();
        setError('');
      } else {
        setError(response.message || 'Erro ao encerrar posição');
      }
    } catch (error) {
      console.error('Erro ao encerrar posição:', error);
      setError(error.message || 'Erro ao encerrar posição');
    } finally {
      setClosingPosition(null);
    }
  };

  const handleRefresh = async () => {
    setRefreshing(true);
    await loadPositions();
    setRefreshing(false);
  };

  const handleShare = (position) => {
    setSelectedPosition(position);
    setShareModalOpen(true);
  };

  const handleCloseShareModal = () => {
    setShareModalOpen(false);
    setSelectedPosition(null);
  };

  const downloadCard = async () => {
    const element = document.getElementById('share-card');
    if (element) {
      try {
        const canvas = await html2canvas(element, {
          backgroundColor: null,
          scale: 2,
          useCORS: true,
          allowTaint: true
        });

        const link = document.createElement('a');
        link.download = `nautilus-trade-${selectedPosition?.symbol || 'position'}.png`;
        link.href = canvas.toDataURL('image/png');
        link.click();
      } catch (error) {
        console.error('Erro ao gerar imagem:', error);
      }
    }
  };

  const formatCurrency = (value, currency = 'USDT') => {
    if (hideValues) return `*** ${currency}`;
    const numValue = parseFloat(value || 0);
    // Para valores muito pequenos (< 0.01), usar mais casas decimais
    if (Math.abs(numValue) < 0.01 && numValue !== 0) {
      return `${numValue.toFixed(6)} ${currency}`;
    }
    // Para valores pequenos (< 1), usar 4 casas decimais
    if (Math.abs(numValue) < 1) {
      return `${numValue.toFixed(4)} ${currency}`;
    }
    // Para valores maiores, usar 2 casas decimais
    return `${numValue.toFixed(2)} ${currency}`;
  };

  const formatPercentage = (value) => {
    // Percentuais permanecem visíveis
    const formatted = parseFloat(value || 0).toFixed(2);
    return `${formatted >= 0 ? '+' : ''}${formatted}%`;
  };

  const formatNumber = (value) => {
    if (hideValues) return '***';
    if (value === null || value === undefined) return '0';
    return new Intl.NumberFormat('pt-BR').format(value);
  };

  const getColorByValue = (value) => {
    if (value > 0) return '#02c076'; // Verde
    if (value < 0) return '#f84960'; // Vermelho
    return '#848e9c'; // Cinza neutro
  };

  const getSideColor = (side) => {
    return side === 'long' ? '#02c076' : '#f84960';
  };

  const getSideIcon = (side) => {
    return side === 'long' ? <TrendingUp /> : <TrendingDown />;
  };

  // Loading state
  if (loading) {
    return (
      <Paper sx={{ p: 2.5, height: 380 }}>
        <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 2, fontSize: '1.1rem' }}>
          <TrendingUp color="primary" sx={{ fontSize: 20 }} />
          Posições Abertas
        </Typography>
        <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
          <Skeleton variant="rectangular" height={60} />
          <Skeleton variant="rectangular" height={40} />
          <Skeleton variant="rectangular" height={40} />
          <Skeleton variant="rectangular" height={40} />
        </Box>
      </Paper>
    );
  }

  // Error state
  if (error) {
    return (
      <Paper sx={{ p: 2.5, height: 380 }}>
        <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 2 }}>
          <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1, fontSize: '1.1rem' }}>
            <TrendingUp color="primary" sx={{ fontSize: 20 }} />
            📊 Posições Abertas
          </Typography>

          <IconButton onClick={handleRefresh} disabled={refreshing} size="small">
            <Refresh />
          </IconButton>
        </Box>

        <Box
          sx={{
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            justifyContent: 'center',
            height: 280,
            bgcolor: 'background.default',
            borderRadius: 1,
            border: `1px dashed ${theme.palette.divider}`,
            p: 2
          }}
        >
          {error.includes('API não configurada') ? (
            <>
              <Lock sx={{ fontSize: 40, color: 'text.secondary', mb: 1.5 }} />
              <Typography variant="subtitle1" color="text.secondary" gutterBottom sx={{ fontSize: '1rem' }}>
                API Bitget não configurada
              </Typography>
              <Typography variant="body2" color="text.secondary" align="center" sx={{ fontSize: '0.85rem' }}>
                Configure suas credenciais da API Bitget para visualizar posições abertas.
              </Typography>
            </>
          ) : (
            <>
              <Warning sx={{ fontSize: 40, color: 'warning.main', mb: 1.5 }} />
              <Typography variant="subtitle1" color="text.secondary" gutterBottom sx={{ fontSize: '1rem' }}>
                Erro ao carregar posições
              </Typography>
              <Typography variant="body2" color="text.secondary" align="center" sx={{ fontSize: '0.85rem', mb: 2 }}>
                {error}
              </Typography>
              <Alert severity="error" sx={{ width: '100%', fontSize: '0.8rem' }}>
                Verifique sua conexão e tente novamente.
              </Alert>
            </>
          )}
        </Box>
      </Paper>
    );
  }

  // No positions state
  if (!positions || positions.length === 0) {
    return (
      <Paper sx={{ p: 2.5, height: 380 }}>
        <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 2 }}>
          <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1, fontSize: '1.1rem' }}>
            <TrendingUp color="primary" sx={{ fontSize: 20 }} />
            📊 Posições Abertas
          </Typography>

          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
            {/* Timer Visual */}
            <Box sx={{ position: 'relative', display: 'inline-flex' }}>
              <CircularProgress
                variant="determinate"
                value={progress}
                size={24}
                thickness={4}
                sx={{
                  color: theme.palette.primary.main,
                  '& .MuiCircularProgress-circle': {
                    strokeLinecap: 'round',
                  }
                }}
              />
              <Box
                sx={{
                  top: 0,
                  left: 0,
                  bottom: 0,
                  right: 0,
                  position: 'absolute',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                }}
              >
                <Schedule sx={{ fontSize: 12, color: 'text.secondary' }} />
              </Box>
            </Box>

            <IconButton onClick={handleRefresh} disabled={refreshing} size="small">
              <Refresh />
            </IconButton>
          </Box>
        </Box>

        <Box
          sx={{
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            justifyContent: 'center',
            height: 280,
            bgcolor: 'background.default',
            borderRadius: 1,
            border: `1px dashed ${theme.palette.divider}`,
            p: 2
          }}
        >
          <TrendingUp sx={{ fontSize: 40, color: 'text.secondary', mb: 1.5 }} />
          <Typography variant="subtitle1" color="text.secondary" gutterBottom sx={{ fontSize: '1rem' }}>
            Nenhuma posição aberta
          </Typography>
          <Typography variant="body2" color="text.secondary" align="center" sx={{ fontSize: '0.85rem' }}>
            Você não possui posições abertas no momento. As posições aparecerão aqui quando você abrir operações na Bitget.
          </Typography>
        </Box>

        {/* Debug Info */}
        {process.env.NODE_ENV === 'development' && debugInfo && (
          <Typography variant="caption" color="text.secondary" sx={{ fontSize: '0.7rem', mt: 1, display: 'block' }}>
            Debug: {debugInfo}
          </Typography>
        )}
      </Paper>
    );
  }

  return (
    <>
      <Paper sx={{ p: 2.5, height: 380, transition: 'all 0.3s ease-in-out' }}>
        <Box display="flex" justifyContent="space-between" alignItems="center" mb={2}>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 2 }}>
            <Typography variant="h6" component="h2">
              📊 Posições Abertas
            </Typography>

            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
              {/* Timer Visual */}
              <Box sx={{ position: 'relative', display: 'inline-flex' }}>
                <CircularProgress
                  variant="determinate"
                  value={progress}
                  size={24}
                  thickness={4}
                  sx={{
                    color: theme.palette.primary.main,
                    '& .MuiCircularProgress-circle': {
                      strokeLinecap: 'round',
                    }
                  }}
                />
                <Box
                  sx={{
                    top: 0,
                    left: 0,
                    bottom: 0,
                    right: 0,
                    position: 'absolute',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                  }}
                >
                  <Schedule sx={{ fontSize: 12, color: theme.palette.primary.main }} />
                </Box>
              </Box>

              {/* Indicador sutil de loading */}
              {loading && (
                <CircularProgress
                  size={16}
                  thickness={4}
                  sx={{
                    color: theme.palette.primary.main,
                    opacity: 0.7
                  }}
                />
              )}
            </Box>
          </Box>

          <Tooltip title="Atualizar">
            <span>
              <IconButton 
                onClick={handleRefresh} 
                disabled={refreshing}
                size="small"
              >
                <Refresh sx={{ 
                  animation: refreshing ? 'spin 1s linear infinite' : 'none',
                  '@keyframes spin': {
                    '0%': { transform: 'rotate(0deg)' },
                    '100%': { transform: 'rotate(360deg)' }
                  }
                }} />
              </IconButton>
            </span>
          </Tooltip>
        </Box>

        {error && (
          <Alert severity="warning" sx={{ mb: 2 }}>
            {error}
          </Alert>
        )}

        {positions.length === 0 ? (
          <Box textAlign="center" py={4}>
            <Typography variant="body1" color="text.secondary">
              Nenhuma posição aberta
            </Typography>
          </Box>
        ) : (
          <TableContainer>
            <Table size="small">
              <TableHead>
                <TableRow>
                  <TableCell align="center">Par</TableCell>
                  <TableCell align="center">Lado</TableCell>
                  <TableCell align="center">Tamanho</TableCell>
                  <TableCell align="center">Alavancagem</TableCell>
                  <TableCell align="center">Preço Entrada</TableCell>
                  <TableCell align="center">Preço Atual</TableCell>
                  <TableCell align="center">PnL Não Realizado</TableCell>
                  <TableCell align="center">ROE</TableCell>
                  <TableCell align="center">Margem</TableCell>
                  <TableCell align="center">Ações</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {positions.map((position, index) => {
                  const leverage = parseFloat(position.leverage) || 1;
                  const pnlPercentage = position.entry_price > 0 
                    ? ((position.mark_price - position.entry_price) / position.entry_price * 100) * (position.side === 'long' ? 1 : -1) * leverage
                    : 0;

                  return (
                    <TableRow key={index} hover>
                      <TableCell align="center">
                        <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 1 }}>
                          <Typography variant="body2" fontWeight="bold">
                            {position.symbol}
                          </Typography>
                          <Tooltip title="Compartilhar operação">
                            <IconButton 
                              size="small" 
                              onClick={() => handleShare(position)}
                              sx={{ 
                                color: theme.palette.primary.main,
                                '&:hover': {
                                  backgroundColor: theme.palette.primary.main + '20'
                                }
                              }}
                            >
                              <Share sx={{ fontSize: 16 }} />
                            </IconButton>
                          </Tooltip>
                        </Box>
                      </TableCell>
                      <TableCell align="center">
                        <Chip
                          icon={getSideIcon(position.side)}
                          label={position.side === 'long' ? 'COMPRA' : 'VENDA'}
                          size="small"
                          sx={{
                            bgcolor: `${getSideColor(position.side)}20`,
                            color: getSideColor(position.side),
                            fontWeight: 'bold'
                          }}
                        />
                      </TableCell>
                      <TableCell align="center">
                        <Typography variant="body2">
                          {formatCurrency(position.size, '')}
                        </Typography>
                      </TableCell>
                      <TableCell align="center">
                        <Typography variant="body2">
                          {position.leverage}x
                        </Typography>
                      </TableCell>
                      <TableCell align="center">
                        <Typography variant="body2">
                          {(() => {
                            const price = parseFloat(position.entry_price || 0);
                            if (Math.abs(price) < 0.01 && price !== 0) {
                              return `$${price.toFixed(8)}`;
                            }
                            if (Math.abs(price) < 1) {
                              return `$${price.toFixed(6)}`;
                            }
                            if (Math.abs(price) < 100) {
                              return `$${price.toFixed(4)}`;
                            }
                            return `$${price.toFixed(3)}`;
                          })()} 
                        </Typography>
                      </TableCell>
                      <TableCell align="center">
                        <Typography variant="body2">
                          {(() => {
                            const price = parseFloat(position.mark_price || 0);
                            if (Math.abs(price) < 0.01 && price !== 0) {
                              return `$${price.toFixed(8)}`;
                            }
                            if (Math.abs(price) < 1) {
                              return `$${price.toFixed(6)}`;
                            }
                            if (Math.abs(price) < 100) {
                              return `$${price.toFixed(4)}`;
                            }
                            return `$${price.toFixed(3)}`;
                          })()} 
                        </Typography>
                      </TableCell>
                      <TableCell align="center">
                        <Typography 
                          variant="body2" 
                          sx={{ color: getColorByValue(position.unrealized_pnl) }}
                          fontWeight="bold"
                        >
                          {formatCurrency(position.unrealized_pnl)}
                        </Typography>
                      </TableCell>
                      <TableCell align="center">
                        <Typography 
                          variant="body2" 
                          sx={{ color: getColorByValue(pnlPercentage) }}
                          fontWeight="bold"
                        >
                          {formatPercentage(pnlPercentage)}
                        </Typography>
                      </TableCell>
                      <TableCell align="center">
                        <Typography variant="body2">
                          {formatCurrency(position.margin_size)}
                        </Typography>
                      </TableCell>
                      <TableCell align="center">
                        <Tooltip title="Encerrar posição">
                          <span>
                            <IconButton 
                              size="small" 
                              onClick={() => handleClosePosition(position)}
                              disabled={closingPosition === position.symbol}
                              sx={{ 
                                color: theme.palette.error.main,
                                '&:hover': {
                                  backgroundColor: theme.palette.error.main + '20'
                                },
                                '&:disabled': {
                                  color: theme.palette.action.disabled
                                }
                              }}
                            >
                              {closingPosition === position.symbol ? (
                                <CircularProgress size={16} />
                              ) : (
                                <Close sx={{ fontSize: 16 }} />
                              )}
                            </IconButton>
                          </span>
                        </Tooltip>
                      </TableCell>
                    </TableRow>
                  );
                })}
              </TableBody>
            </Table>
          </TableContainer>
        )}

        {positions.length > 0 && (
          <Box mt={2} textAlign="center">
            <Typography variant="caption" color="text.secondary">
              Total: {positions.length} posição{positions.length !== 1 ? 'ões' : ''}
            </Typography>
          </Box>
        )}
      </Paper>

      {/* Share Modal */}
      <Dialog 
        open={shareModalOpen} 
        onClose={handleCloseShareModal}
        maxWidth="sm"
        fullWidth
        PaperProps={{
          sx: { 
            maxHeight: '90vh',
            height: 'auto'
          }
        }}
      >
        <DialogContent sx={{ 
          p: 3, 
          backgroundColor: '#f5f5f5',
          maxHeight: '80vh',
          overflowY: 'auto',
          overflowX: 'hidden'
        }}>
          <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2 }}>
            <Typography variant="h6">Compartilhar Operação</Typography>
            <IconButton onClick={handleCloseShareModal} size="small">
              <Close />
            </IconButton>
          </Box>

          <Box sx={{ display: 'flex', justifyContent: 'center', mb: 3 }}>
            <ShareCard position={selectedPosition} />
          </Box>

          <Box sx={{ display: 'flex', gap: 2, justifyContent: 'center' }}>
            <Button 
              variant="contained" 
              startIcon={<Download />}
              onClick={downloadCard}
              sx={{ 
                backgroundColor: '#00bcd4',
                '&:hover': {
                  backgroundColor: '#0097a7'
                }
              }}
            >
              Baixar Imagem
            </Button>
          </Box>
        </DialogContent>
      </Dialog>
    </>
  );
};

export default OpenPositions;
